I'll create a comprehensive effect layer system with Logger and Database services, showing how to compose them and inject them into a program.

```scala
import scala.util.{Try, Success, Failure}
import scala.concurrent.{ExecutionContext, Future}
import scala.collection.mutable

// === Effect Layer Definitions ===

// Logger Service Interface
trait Logger {
  def info(msg: String): Unit
  def error(msg: String): Unit
}

// Database Service Interface
trait Database {
  def save(key: String, value: String): Try[Unit]
  def get(key: String): Try[Option[String]]
  def delete(key: String): Try[Unit]
}

// Effect Type - Using a simple effect system with type classes
trait Effect[R] {
  def run[A](fa: R => A): A
}

// Concrete implementations of services
object LoggerService {
  def apply(): Logger = new Logger {
    def info(msg: String): Unit = println(s"[INFO] $msg")
    def error(msg: String): Unit = println(s"[ERROR] $msg")
  }
}

object DatabaseService {
  def apply(): Database = new Database {
    private val storage = mutable.Map[String, String]()

    def save(key: String, value: String): Try[Unit] = {
      try {
        storage.put(key, value)
        Success(())
      } catch {
        case e: Exception => Failure(e)
      }
    }

    def get(key: String): Try[Option[String]] = {
      try {
        Success(storage.get(key))
      } catch {
        case e: Exception => Failure(e)
      }
    }

    def delete(key: String): Try[Unit] = {
      try {
        storage.remove(key)
        Success(())
      } catch {
        case e: Exception => Failure(e)
      }
    }
  }
}

// === Layer Composition ===

// Layer trait that represents a service with dependencies
trait Layer[-R, +A] {
  def build(r: R): A
  def compose[B](other: Layer[A, B]): Layer[R, B] = new Layer[R, B] {
    def build(r: R): B = other.build(build(r))
  }
}

// Logger Layer
object LoggerLayer {
  def apply(): Layer[Any, Logger] = new Layer[Any, Logger] {
    def build(r: Any): Logger = LoggerService()
  }
}

// Database Layer
object DatabaseLayer {
  def apply(): Layer[Any, Database] = new Layer[Any, Database] {
    def build(r: Any): Database = DatabaseService()
  }
}

// Composed Layer - Both services
object ComposedLayer {
  def apply(): Layer[Any, (Logger, Database)] = new Layer[Any, (Logger, Database)] {
    def build(r: Any): (Logger, Database) = {
      val logger = LoggerService()
      val database = DatabaseService()
      (logger, database)
    }
  }
}

// === Program Using the Layers ===

// Program that uses both services
class UserService(logger: Logger, database: Database) {
  def createUser(username: String, email: String): Try[Unit] = {
    logger.info(s"Creating user: $username")

    val result = for {
      _ <- database.save(s"user:$username", email)
      _ <- database.save(s"email:$email", username)
    } yield ()

    result match {
      case Success(_) => 
        logger.info(s"User $username created successfully")
        Success(())
      case Failure(e) => 
        logger.error(s"Failed to create user $username: ${e.getMessage}")
        Failure(e)
    }
  }

  def getUser(username: String): Try[Option[String]] = {
    logger.info(s"Retrieving user: $username")

    database.get(s"user:$username") match {
      case Success(Some(email)) => 
        logger.info(s"User $username found with email: $email")
        Success(Some(email))
      case Success(None) => 
        logger.info(s"User $username not found")
        Success(None)
      case Failure(e) => 
        logger.error(s"Database error retrieving user $username: ${e.getMessage}")
        Failure(e)
    }
  }

  def deleteUser(username: String): Try[Unit] = {
    logger.info(s"Deleting user: $username")

    val result = for {
      emailOpt <- database.get(s"user:$username")
      _ <- emailOpt match {
        case Some(email) => database.delete(s"user:$username")
        case None => Success(())
      }
      _ <- database.delete(s"email:$email")
    } yield ()

    result match {
      case Success(_) => 
        logger.info(s"User $username deleted successfully")
        Success(())
      case Failure(e) => 
        logger.error(s"Failed to delete user $username: ${e.getMessage}")
        Failure(e)
    }
  }
}

// === Dependency Injection Setup ===

// Effect-based program runner
object Program {
  def run(): Unit = {
    // Create the composed layer
    val layer = ComposedLayer()

    // Build the services
    val (logger, database) = layer.build(())

    // Create the program with injected dependencies
    val userService = new UserService(logger, database)

    // Run some operations
    println("=== User Management Demo ===")

    // Create users
    userService.createUser("john_doe", "john@example.com")
    userService.createUser("jane_smith", "jane@example.com")

    // Retrieve users
    userService.getUser("john_doe")
    userService.getUser("nonexistent_user")

    // Delete a user
    userService.deleteUser("john_doe")

    // Try to retrieve deleted user
    userService.getUser("john_doe")
  }
}

// === Alternative: Using Cats-Effect Style ===

// If you want to use a more advanced effect system like Cats-Effect
trait Effectful[R, A] {
  def run(implicit R: R): A
}

// Simple effect runner
object EffectRunner {
  def runEffect[R, A](effect: Effectful[R, A], context: R): A = {
    effect.run(context)
  }
}

// Enhanced version with effect type
case class LoggerEffect(msg: String, level: String) {
  def run(logger: Logger): Unit = level match {
    case "info" => logger.info(msg)
    case "error" => logger.error(msg)
    case _ => logger.info(msg)
  }
}

// Enhanced program with effect composition
object EnhancedProgram {
  def run(): Unit = {
    val logger = LoggerService()
    val database = DatabaseService()

    // Simulate effect composition
    val effects = List(
      LoggerEffect("Starting user management", "info"),
      LoggerEffect("Creating test users", "info")
    )

    effects.foreach(_.run(logger))

    val userService = new UserService(logger, database)
    userService.createUser("alice", "alice@example.com")
    userService.getUser("alice")
  }
}

// === Main Execution ===

object Main extends App {
  println("=== Basic Layer Composition Demo ===")
  Program.run()

  println("\n=== Enhanced Effect Demo ===")
  EnhancedProgram.run()

  // Demonstrate layer composition
  println("\n=== Layer Composition Demo ===")
  val loggerLayer = LoggerLayer()
  val databaseLayer = DatabaseLayer()
  val composedLayer = loggerLayer.compose(databaseLayer)

  val (logger, database) = composedLayer.build(())
  println("Successfully composed layers and injected dependencies")
  logger.info("Layer composition working correctly")
  database.save("test", "value")
}
```

This implementation provides:

## Key Features:

1. **Service Interfaces**: Clean separation of `Logger` and `Database` services
2. **Layer Composition**: `Layer` trait that allows composing services
3. **Dependency Injection**: Services are injected into the program
4. **Error Handling**: Uses `Try` for safe operations
5. **Effect System**: Shows both simple and enhanced effect patterns

## How it works:

1. **Service Definitions**: Define interfaces for Logger and Database
2. **Layer Creation**: Create layers that build service instances
3. **Composition**: Compose layers using the `compose` method
4. **Injection**: Inject dependencies into the program
5. **Usage**: Program uses both services through dependency injection

## Usage Patterns:

```scala
// Simple usage
val logger = LoggerService()
val database = DatabaseService()
val userService = new UserService(logger, database)

// Layer composition
val composedLayer = LoggerLayer().compose(DatabaseLayer())
val (logger, database) = composedLayer.build(())

// Run the program
Program.run()
```

The system is flexible and can be extended with more services, different effect types, or integrated with dependency injection frameworks like Cats-IOC or MacWire.

Here's a typeahead search Observable using RxJS that meets all your requirements:

```javascript
import { of, EMPTY } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, catchError } from 'rxjs/operators';

// Assuming you have a search API function that returns Observable<Result[]>
const searchApi = (query) => {
  // Your API call implementation
  // Example:
  // return httpClient.get<Result[]>(`/api/search?q=${query}`);
};

const typeaheadSearch = (input$) => {
  return input$.pipe(
    debounceTime(250),           // Wait 250ms after user stops typing
    distinctUntilChanged(),      // Only emit if value is different from previous
    switchMap(query => {
      // Return EMPTY if query is empty to avoid unnecessary API calls
      if (!query.trim()) {
        return EMPTY;
      }
      // Cancel in-flight requests due to switchMap
      return searchApi(query).pipe(
        catchError(error => {
          // Handle errors appropriately
          console.error('Search error:', error);
          return of([]); // Return empty array on error
        })
      );
    })
  );
};

// Usage example:
// const results$ = typeaheadSearch(input$);
// results$.subscribe(results => {
//   // Handle search results
//   console.log(results);
// });
```

**Key features explained:**

1. **`debounceTime(250)`** - Waits 250ms after the user stops typing before processing the input
2. **`distinctUntilChanged()`** - Drops duplicate values (prevents unnecessary API calls for same input)
3. **`switchMap`** - Automatically cancels previous in-flight requests when new input arrives
4. **`EMPTY`** - Returns an empty observable for empty queries to prevent API calls
5. **`catchError`** - Handles API errors gracefully without breaking the stream

**Alternative implementation with more explicit error handling:**

```javascript
import { of, EMPTY, throwError } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, catchError, tap } from 'rxjs/operators';

const typeaheadSearch = (input$) => {
  return input$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    switchMap(query => {
      if (!query.trim()) {
        return EMPTY;
      }

      return searchApi(query).pipe(
        catchError(error => {
          // Log error but don't break the stream
          console.error('Search error:', error);
          return of([]); // Return empty array instead of throwing
        })
      );
    })
  );
};
```

This implementation ensures that:
- Requests are debounced by 250ms
- Duplicate queries are filtered out
- Previous requests are cancelled when new input arrives (via `switchMap`)
- Empty queries don't trigger API calls
- Errors are handled gracefully

Here's how to combine three Observables into a single Observable<ViewModel> that emits when any of them changes:

```typescript
import { combineLatest } from 'rxjs';
import { map } from 'rxjs/operators';

interface User {
  id: string;
  name: string;
  email: string;
}

interface Settings {
  notifications: boolean;
  darkMode: boolean;
  language: string;
}

interface Theme {
  primaryColor: string;
  secondaryColor: string;
  fontSize: number;
}

interface ViewModel {
  user: User;
  settings: Settings;
  theme: Theme;
  timestamp: number;
}

// Assuming you have these observables defined somewhere
// const user$ = ...;
// const settings$ = ...;
// const theme$ = ...;

const viewModel$ = combineLatest([user$, settings$, theme$]).pipe(
  map(([user, settings, theme]) => ({
    user,
    settings,
    theme,
    timestamp: Date.now()
  }))
);
```

**Alternative approach using `merge` with `switchMap` if you want to emit immediately when any source changes:**

```typescript
import { merge, of } from 'rxjs';
import { switchMap, map } from 'rxjs/operators';

// If you want to emit immediately when any source emits
const viewModel$ = merge(user$, settings$, theme$).pipe(
  switchMap(() => combineLatest([user$, settings$, theme$])),
  map(([user, settings, theme]) => ({
    user,
    settings,
    theme,
    timestamp: Date.now()
  }))
);
```

**Or if you want to use `withLatestFrom` for more control:**

```typescript
import { combineLatest } from 'rxjs';
import { map } from 'rxjs/operators';

const viewModel$ = combineLatest([user$, settings$, theme$]).pipe(
  map(([user, settings, theme]) => ({
    user,
    settings,
    theme,
    timestamp: Date.now()
  }))
);
```

**Key points:**

1. **`combineLatest`** - Combines the latest values from all three observables and emits whenever ANY of them emits
2. **`map`** - Transforms the combined values into your `ViewModel` interface
3. **Type safety** - The TypeScript compiler will ensure type safety throughout the pipeline
4. **Timestamp** - Added for debugging/monitoring purposes (optional)

The first approach using `combineLatest` is the most common and recommended solution as it ensures you always have the latest values from all sources when emitting a new ViewModel.

Here's how to process a stream of file uploads with concurrency control using `mergeMap`:

```typescript
import { Observable, of, merge } from 'rxjs';
import { mergeMap, take, tap } from 'rxjs/operators';

// Assuming uploadFile returns Observable<Progress>
// const uploadFile = (f: File): Observable<Progress> => ...

// Method 1: Using mergeMap with concurrency control
function processFileUploads$(fileStream: Observable<File>): Observable<Progress> {
  return fileStream.pipe(
    mergeMap(file => uploadFile(file), 3) // 3 concurrent uploads
  );
}

// Method 2: More explicit approach with buffer and mergeMap
function processFileUploadsBuffered$(fileStream: Observable<File>): Observable<Progress> {
  return fileStream.pipe(
    mergeMap(file => {
      return uploadFile(file);
    }, 3) // Limit to 3 concurrent uploads
  );
}

// Method 3: If you want to handle errors gracefully
function processFileUploadsWithErrorHandling$(fileStream: Observable<File>): Observable<Progress> {
  return fileStream.pipe(
    mergeMap(file => 
      uploadFile(file).pipe(
        // Handle errors per file
        catchError(error => {
          console.error(`Upload failed for file: ${file.name}`, error);
          return of(null); // or re-throw if you want to stop the stream
        })
      )
    , 3)
  );
}

// Method 4: With progress tracking and completion
function processFileUploadsWithTracking$(fileStream: Observable<File>): Observable<Progress> {
  return fileStream.pipe(
    mergeMap(file => {
      console.log(`Starting upload for: ${file.name}`);
      return uploadFile(file).pipe(
        tap(progress => {
          console.log(`${file.name}: ${Math.round(progress.loaded / progress.total * 100)}%`);
        })
      );
    }, 3)
  );
}

// Usage example:
const fileInput = document.getElementById('fileInput') as HTMLInputElement;
const fileStream = fromEvent(fileInput, 'change').pipe(
  map((event: any) => Array.from(event.target.files) as File[])
);

// Process uploads with max 3 concurrent
const uploadProgress$ = processFileUploads$(fileStream);

// Subscribe to get progress updates
uploadProgress$.subscribe({
  next: (progress: Progress) => {
    console.log('Upload progress:', progress);
  },
  error: (error) => {
    console.error('Upload error:', error);
  },
  complete: () => {
    console.log('All uploads completed');
  }
});
```

Key points:

1. **Concurrency Control**: The second parameter of `mergeMap` (3) limits concurrent uploads to 3
2. **Stream Processing**: Files are processed as they arrive in the stream
3. **Progress Tracking**: Each upload returns `Observable<Progress>` which can be subscribed to for real-time updates
4. **Error Handling**: You can add `catchError` to handle individual file upload failures
5. **Memory Efficient**: `mergeMap` handles the concurrency without blocking the stream

The `mergeMap` operator with the concurrency parameter is perfect for this use case because:
- It processes the file stream as items arrive
- It limits concurrent operations to 3
- It maintains the order of items in the output stream
- It handles backpressure automatically
- It continues processing even if individual uploads fail

Here's a detailed explanation of the difference between `Subject<T>` and `BehaviorSubject<T>` with a concrete example for a 'currentUser' state stream:

## Key Differences

**Subject<T>**: 
- Does NOT replay the last value to new subscribers
- Only emits new values that occur after subscription
- If you subscribe late, you miss all previous values

**BehaviorSubject<T>**:
- REPLAYS the last emitted value to new subscribers
- Emits the most recent value immediately upon subscription
- Perfect for state streams where late subscribers need the current state

## Concrete Example

```typescript
import { BehaviorSubject, Subject } from 'rxjs';

// Example 1: Using Subject<T> - Problematic for currentUser
const currentUserSubject = new Subject<{name: string, id: number}>();

// Simulate some initial data
currentUserSubject.next({name: 'Alice', id: 1});
currentUserSubject.next({name: 'Bob', id: 2});

// Later, a new subscriber subscribes (e.g., after app loads)
setTimeout(() => {
  currentUserSubject.subscribe(user => {
    console.log('Subject - New subscriber gets:', user); 
    // Output: nothing (no previous values sent)
  });
}, 1000);

// Example 2: Using BehaviorSubject<T> - Correct approach
const currentUserBehaviorSubject = new BehaviorSubject<{name: string, id: number}>({
  name: 'Default User', 
  id: 0
});

// Simulate some initial data
currentUserBehaviorSubject.next({name: 'Alice', id: 1});
currentUserBehaviorSubject.next({name: 'Bob', id: 2});

// Later, a new subscriber subscribes
setTimeout(() => {
  currentUserBehaviorSubject.subscribe(user => {
    console.log('BehaviorSubject - New subscriber gets:', user); 
    // Output: {name: 'Bob', id: 2} - the last emitted value
  });
}, 1000);

// Even if we subscribe immediately, we get the initial value
const immediateSubscription = currentUserBehaviorSubject.subscribe(user => {
  console.log('Immediate subscription gets:', user); 
  // Output: {name: 'Bob', id: 2} - the last emitted value
});
```

## Real-World Usage Example

```typescript
import { BehaviorSubject } from 'rxjs';

class UserService {
  private currentUserSubject = new BehaviorSubject<{name: string, id: number} | null>(null);

  // Public observable for components to subscribe to
  public currentUser$ = this.currentUserSubject.asObservable();

  // Method to update current user
  setCurrentUser(user: {name: string, id: number}) {
    this.currentUserSubject.next(user);
  }

  // Method to clear current user
  clearCurrentUser() {
    this.currentUserSubject.next(null);
  }
}

// Usage in components
const userService = new UserService();

// Component A - subscribes immediately
userService.currentUser$.subscribe(user => {
  console.log('Component A:', user); // Gets initial null value
});

// Component B - subscribes later (e.g., after app loads)
setTimeout(() => {
  userService.currentUser$.subscribe(user => {
    console.log('Component B:', user); // Gets the most recent value (could be null, or last user)
  });
}, 2000);

// Update user
userService.setCurrentUser({name: 'John', id: 123});
// Both components receive the update
```

## Why BehaviorSubject is Better for currentUser State

1. **Immediate State Availability**: New subscribers get the current state immediately
2. **No Race Conditions**: Components don't need to wait for data
3. **Consistent UX**: Users see the current state regardless of when they navigate to a component
4. **Default Value Support**: You can provide an initial value that all subscribers see

## When to Use Each

**Use Subject<T> when**:
- You only care about new values
- You don't need to replay previous values
- You're building custom observables where replaying isn't needed

**Use BehaviorSubject<T> when**:
- You have state that needs to be shared
- Late subscribers need immediate access to current state
- You're building a store or state management system
- You want to provide a default initial value

