  timestamp: Date;
}

interface AggregateState<T> {
  id: string;
  version: number;
  state: T;
}

// Core loadAggregate function with snapshot awareness
async function loadAggregate<T>(
  aggregateId: string,
  eventStore: {
    getEvents: (aggregateId: string, fromVersion?: number) => Promise<Event<any>[]>;
    getSnapshot: (aggregateId: string) => Promise<AggregateSnapshot<T> | null>;
    saveSnapshot: (snapshot: AggregateSnapshot<T>) => Promise<void>;
  },
  applyEvent: (state: T, event: Event<any>) => T,
  initialState: T,
  snapshotThreshold: number = 100,
  maxReplayEvents: number = 10000
): Promise<AggregateState<T>> {

  // Try to load snapshot first
  const snapshot = await eventStore.getSnapshot(aggregateId);

  if (snapshot) {
    // Check if snapshot is still valid (optional version checking)
    const eventsSinceSnapshot = await eventStore.getEvents(
      aggregateId, 
      snapshot.version + 1
    );

    // If too many events since snapshot, replay from beginning
    if (eventsSinceSnapshot.length > maxReplayEvents) {
      return replayFullEventStream(aggregateId, eventStore, applyEvent, initialState);
    }

    // Apply events since snapshot to snapshot state
    let currentState = { ...snapshot.state };
    let currentVersion = snapshot.version;

    for (const event of eventsSinceSnapshot) {
      if (event.version !== currentVersion + 1) {
        throw new Error(`Event version mismatch for aggregate ${aggregateId}`);
      }
      currentState = applyEvent(currentState, event);
      currentVersion = event.version;
    }

    return {
      id: aggregateId,
      version: currentVersion,
      state: currentState
    };
  }

  // No snapshot available, replay from beginning
  return replayFullEventStream(aggregateId, eventStore, applyEvent, initialState);
}

// Helper function for full event stream replay
async function replayFullEventStream<T>(
  aggregateId: string,
  eventStore: {
    getEvents: (aggregateId: string, fromVersion?: number) => Promise<Event<any>[]>;
  },
  applyEvent: (state: T, event: Event<any>) => T,
  initialState: T
): Promise<AggregateState<T>> {
  const events = await eventStore.getEvents(aggregateId);

  if (events.length === 0) {
    return {
      id: aggregateId,
      version: 0,
      state: initialState
    };
  }

  let currentState = initialState;
  let currentVersion = 0;

  for (const event of events) {
    if (event.version !== currentVersion + 1) {
      throw new Error(`Event version mismatch for aggregate ${aggregateId}`);
    }
    currentState = applyEvent(currentState, event);
    currentVersion = event.version;
  }

  return {
    id: aggregateId,
    version: currentVersion,
    state: currentState
  };
}

// Example usage
interface OrderState {
  items: string[];
  total: number;
  status: 'pending' | 'completed' | 'cancelled';
}

const orderApplyEvent = (state: OrderState, event: Event<any>): OrderState => {
  switch (event.type) {
    case 'OrderCreated':
      return {
        ...state,
        items: event.payload.items,
        total: event.payload.total,
        status: 'pending'
      };
    case 'OrderItemAdded':
      return {
        ...state,
        items: [...state.items, event.payload.item],
        total: state.total + event.payload.price
      };
    case 'OrderCompleted':
      return {
        ...state,
        status: 'completed'
      };
    default:
      return state;
  }
};

// Usage example
async function example() {
  const order = await loadAggregate<OrderState>(
    'order-123',
    eventStore,
    orderApplyEvent,
    { items: [], total: 0, status: 'pending' },
    50, // snapshot every 50 events
    1000 // max events to replay
  );
}
```

This implementation provides a flexible approach that combines the benefits of both strategies, using snapshots for performance while falling back to full replay when necessary.

