          actions: [
            'setEmail',
            'validateEmail'
          ]
        },
        NEXT: [
          {
            guard: 'isEmailValid',
            target: 'password'
          },
          {
            actions: 'setEmailError'
          }
        ]
      }
    },
    password: {
      entry: [
        'clearPasswordErrors'
      ],
      on: {
        UPDATE_PASSWORD: {
          actions: [
            'setPassword',
            'clearPasswordErrors'
          ]
        },
        VALIDATE_PASSWORD: {
          actions: [
            'setPassword',
            'validatePassword'
          ]
        },
        BACK: 'email',
        NEXT: [
          {
            guard: 'isPasswordValid',
            target: 'confirm'
          },
          {
            actions: 'setPasswordError'
          }
        ]
      }
    },
    confirm: {
      entry: [
        'clearConfirmErrors'
      ],
      on: {
        UPDATE_CONFIRM: {
          actions: [
            'setConfirm',
            'clearConfirmErrors'
          ]
        },
        VALIDATE_CONFIRM: {
          actions: [
            'setConfirm',
            'validateConfirm'
          ]
        },
        BACK: 'password',
        NEXT: [
          {
            guard: 'isConfirmValid',
            target: 'submit'
          },
          {
            actions: 'setConfirmError'
          }
        ]
      }
    },
    submit: {
      entry: [
        'clearSubmitErrors'
      ],
      invoke: {
        src: 'validateEmail',
        input: ({ context }) => ({ email: context.email }),
        onDone: [
          {
            guard: ({ event }) => event.output.valid,
            target: 'submitting'
          },
          {
            actions: [
              'setEmailError',
              'setEmailInvalid'
            ],
            target: 'email'
