```javascript
// State type definition
class ShoppingCartState {
    constructor() {
        this.cartId = null;
        this.items = [];
        this.createdAt = null;
        this.updatedAt = null;
    }
}

// Event type definitions
class CartCreatedEvent {
    constructor(cartId, timestamp) {
        this.type = 'CartCreated';
        this.cartId = cartId;
        this.timestamp = timestamp;
    }
}

class ItemAddedEvent {
    constructor(productId, productName, quantity, price, timestamp) {
        this.type = 'ItemAdded';
        this.productId = productId;
        this.productName = productName;
        this.quantity = quantity;
        this.price = price;
        this.timestamp = timestamp;
    }
}

class ItemRemovedEvent {
    constructor(productId, timestamp) {
        this.type = 'ItemRemoved';
        this.productId = productId;
        this.timestamp = timestamp;
    }
}

// Initial state
const initialCartState = new ShoppingCartState();

// Evolve function
function evolve(state, event) {
    const newState = JSON.parse(JSON.stringify(state)); // Deep copy

    switch (event.type) {
        case 'CartCreated':
            newState.cartId = event.cartId;
            newState.createdAt = event.timestamp;
            newState.updatedAt = event.timestamp;
            break;

        case 'ItemAdded':
            // Check if item already exists in cart
            const existingItemIndex = newState.items.findIndex(item => item.productId === event.productId);

            if (existingItemIndex >= 0) {
                // Update existing item quantity
                newState.items[existingItemIndex].quantity += event.quantity;
                newState.items[existingItemIndex].updatedAt = event.timestamp;
            } else {
                // Add new item
                newState.items.push({
                    productId: event.productId,
                    productName: event.productName,
                    quantity: event.quantity,
                    price: event.price,
                    createdAt: event.timestamp,
                    updatedAt: event.timestamp
                });
            }
            newState.updatedAt = event.timestamp;
            break;

        case 'ItemRemoved':
            // Remove item by productId
            newState.items = newState.items.filter(item => item.productId !== event.productId);
            newState.updatedAt = event.timestamp;
            break;

        default:
            throw new Error(`Unknown event type: ${event.type}`);
    }

    return newState;
}

